#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include <cuda_runtime.h>

extern "C" {
#include "reference.h"
}

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

const int max_iter = 1000;
const float threshold = 1e-16f;

#define CUDA_CHECK(call)                                                         \
  do {                                                                           \
    cudaError_t err__ = (call);                                                  \
    if (err__ != cudaSuccess) {                                                  \
      fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,           \
              cudaGetErrorString(err__));                                        \
      exit(EXIT_FAILURE);                                                        \
    }                                                                            \
  } while (0)

int *random_pages(int n, unsigned int *noutlinks, int divisor){
  int i, j, k;
  int *pages = (int*) malloc((size_t)n * n * sizeof(int));

  if (0 >= divisor) {
    fprintf(stderr, "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n", divisor);
    exit(1);
  }

  for(i=0; n > i; ++i){
    noutlinks[i] = 0;
    for(j=0; n > j; ++j){
      if(j != i && (abs(rand())%divisor == 0)){
        pages[(size_t)i*n+j] = 1;
        noutlinks[i] += 1;
      }
    }

    if(0 == noutlinks[i]){
      do { k = abs(rand()) % n; } while ( i == k);
      pages[(size_t)i*n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val){
  int i;
  for(i=0; n > i; ++i){
    a[i] = val;
  }
}

void usage(char *argv[]){
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
      " [-t threshold] [-q divsor for zero density]\n", argv[0]);
}

static struct option size_opts[] =
{
  {"number of pages", 1, NULL, 'n'},
  {"max number of iterations", 1, NULL, 'i'},
  {"minimum threshold", 1, NULL, 't'},
  {"divisor for zero density", 1, NULL, 'q'},
  { 0, 0, 0}
};

float maximum_dif(float *difs, int n){
  int i;
  float max = 0.0f;
  for(i=0; n > i; ++i){
    max = max < difs[i] ? difs[i] : max;
  }
  return max;
}

__global__ void map_kernel(const int *pages,
                           const float *page_ranks,
                           float *maps,
                           const unsigned int *noutlinks,
                           int n)
{
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i < n) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    size_t base = (size_t)i * (size_t)n;
    for (int j = 0; j < n; ++j) {
      maps[base + j] = pages[base + j] * outbound_rank;
    }
  }
}

__global__ void reduce_kernel(float *page_ranks,
                              const float *maps,
                              int n,
                              float *diffs)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j < n) {
    float new_rank;
    float old_rank;
    old_rank = page_ranks[j];
    new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank = new_rank + maps[(size_t)i * (size_t)n + (size_t)j];
    }
    new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
    diffs[j] = fmaxf(fabsf(new_rank - old_rank), diffs[j]);
    page_ranks[j] = new_rank;
  }
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1){
    switch(opt){
      case 'n':
        n = atoi(optarg);
        break;
      case 'i':
        iter = atoi(optarg);
        break;
      case 't':
        thresh = atof(optarg);
        break;
      case 'q':
        divisor = atoi(optarg);
        break;
      default:
        usage(argv);
        exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * (size_t)n * sizeof(float);
  size_t link_size = (size_t)n * sizeof(unsigned int);
  size_t pages_size = (size_t)n * (size_t)n * sizeof(int);

  page_ranks = (float*)malloc(rank_size);
  maps = (float*)malloc(map_size);
  noutlinks = (unsigned int*)malloc(link_size);

  max_diff = max_diff_ref = 99.0f;

  for (i = 0; n > i; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n, noutlinks, divisor);
  init_array(page_ranks, n, 1.0f / (float) n);

  float *diffs;
  diffs  = (float*) malloc(rank_size);
  memset(diffs, 0, rank_size);

  int block_size = BLOCK_SIZE > n ? n : BLOCK_SIZE;
  if (block_size <= 0) block_size = 1;
  int grid_size = (n + block_size - 1) / block_size;

  double ktime = 0.0;

  int *d_pages = NULL;
  float *d_maps = NULL;
  float *d_page_ranks = NULL;
  unsigned int *d_noutlinks = NULL;
  float *d_diffs = NULL;

  if (n > 0) {
    CUDA_CHECK(cudaMalloc((void**)&d_pages, pages_size));
    CUDA_CHECK(cudaMalloc((void**)&d_maps, map_size));
    CUDA_CHECK(cudaMalloc((void**)&d_page_ranks, rank_size));
    CUDA_CHECK(cudaMalloc((void**)&d_noutlinks, link_size));
    CUDA_CHECK(cudaMalloc((void**)&d_diffs, rank_size));

    CUDA_CHECK(cudaMemcpy(d_pages, pages, pages_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_page_ranks, page_ranks, rank_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_noutlinks, noutlinks, link_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice));
  }

  for (t = 1; iter >= t && thresh <= max_diff; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    if (n > 0) {
      map_kernel<<<grid_size, block_size>>>(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
      reduce_kernel<<<grid_size, block_size>>>(d_page_ranks, d_maps, n, d_diffs);
      CUDA_CHECK(cudaGetLastError());
      CUDA_CHECK(cudaDeviceSynchronize());
    }

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double> >(end - start).count();

    if (n > 0) {
      CUDA_CHECK(cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost));
    }
    max_diff = maximum_dif(diffs, n);
  }

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t = 1; iter >= t && thresh <= max_diff_ref; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  if (d_pages) CUDA_CHECK(cudaFree(d_pages));
  if (d_maps) CUDA_CHECK(cudaFree(d_maps));
  if (d_page_ranks) CUDA_CHECK(cudaFree(d_page_ranks));
  if (d_noutlinks) CUDA_CHECK(cudaFree(d_noutlinks));
  if (d_diffs) CUDA_CHECK(cudaFree(d_diffs));

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);
  return 0;
}
